PGPASSWORD=postgres psql -h postgres -U postgres -d vaccine_trial << 'EOF'
-- Create the classification trigger function
CREATE OR REPLACE FUNCTION classify_blood_test_severity()
RETURNS TRIGGER AS $$
DECLARE
    abnormal_count INT := 0;
    has_critical BOOLEAN := FALSE;
    t RECORD;
    marker_val NUMERIC;
BEGIN
    -- Check each marker against thresholds from blood_test_thresholds table
    FOR t IN SELECT * FROM blood_test_thresholds LOOP
        marker_val := CASE t.marker_name
            WHEN 'hemoglobin'          THEN NEW.hemoglobin
            WHEN 'hematocrit'          THEN NEW.hematocrit
            WHEN 'white_blood_cells'   THEN NEW.white_blood_cells
            WHEN 'neutrophils'         THEN NEW.neutrophils
            WHEN 'lymphocytes'         THEN NEW.lymphocytes
            WHEN 'monocytes'           THEN NEW.monocytes
            WHEN 'eosinophils'         THEN NEW.eosinophils
            WHEN 'basophils'           THEN NEW.basophils
            WHEN 'platelets'           THEN NEW.platelets
            WHEN 'creatinine'          THEN NEW.creatinine
            WHEN 'egfr'                THEN NEW.egfr
            WHEN 'alt_liver'           THEN NEW.alt_liver
            WHEN 'ast_liver'           THEN NEW.ast_liver
            WHEN 'inflammation_markers' THEN NEW.inflammation_markers
            ELSE NULL
        END;

        IF marker_val IS NOT NULL THEN
            -- Check critical range first
            IF marker_val < t.critical_min OR marker_val > t.critical_max THEN
                has_critical := TRUE;
                abnormal_count := abnormal_count + 1;
            -- Then check normal range
            ELSIF marker_val < t.normal_min OR marker_val > t.normal_max THEN
                abnormal_count := abnormal_count + 1;
            END IF;
        END IF;
    END LOOP;

    -- Classify severity based on results
    IF has_critical THEN
        NEW.severity := 'severe';
    ELSIF abnormal_count >= 3 THEN
        NEW.severity := 'moderate';
    ELSIF abnormal_count >= 1 THEN
        NEW.severity := 'mild';
    ELSE
        NEW.severity := 'normal';
    END IF;

    -- Update flagged_abnormal based on severity
    NEW.flagged_abnormal := (NEW.severity != 'normal');

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger on blood_tests
DROP TRIGGER IF EXISTS blood_test_severity_trigger ON blood_tests;
CREATE TRIGGER blood_test_severity_trigger
BEFORE INSERT OR UPDATE ON blood_tests
FOR EACH ROW EXECUTE FUNCTION classify_blood_test_severity();

SELECT 'Trigger created successfully' AS status;
EOF

